import{_ as p,C as t,o as c,c as g,j as e,a as n,E as i,a3 as m}from"./chunks/framework.gsMzR_Kb.js";const y=JSON.parse('{"title":"太上感应篇","description":"一篇从善恶感应落到日用警策的劝善短文。","frontmatter":{"title":"太上感应篇","description":"一篇从善恶感应落到日用警策的劝善短文。","category":"guide","aliases":["太上感应篇","感应篇","taishang ganying pian"],"source":["《太上感应篇》"]},"headers":[],"relativePath":"daoism/starter-texts/taishang-ganying-pian.md","filePath":"daoism/starter-texts/taishang-ganying-pian.md","lastUpdated":1777132262000}'),u={name:"daoism/starter-texts/taishang-ganying-pian.md"};function b(x,a,_,P,f,q){const r=t("DaoReadingPrelude"),o=t("DaoOriginalReading"),l=t("DaoLineGuide"),s=t("DaoPinyinGlossary"),d=t("DaoParallelReading"),h=t("DaoKeywordCards");return c(),g("div",null,[a[0]||(a[0]=e("h1",{id:"太上感应篇",tabindex:"-1"},[n("太上感应篇 "),e("a",{class:"header-anchor",href:"#太上感应篇","aria-label":'Permalink to "太上感应篇"'},"​")],-1)),i(r,{title:"先抓住感应总纲，再看善恶条目",summary:"这篇不从玄理起，而是直接立出“祸福无门，惟人自召”的总纲。更适合的进入方式，是先顺着原文感受整篇的警策语气，再按总纲、善行、恶行、改悔四层慢慢分开读。",points:[{label:"先读",text:"先把开篇总纲与结尾改悔完整读一遍。"},{label:"再辨",text:"看善恶条目怎样从日用细处展开。"},{label:"后想",text:"最后回到“转祸为福”的余地，不把全篇只读成惩戒。"}],hint:"这篇篇幅较长，第一次读不必逐条硬记，可先抓住总纲、善行举要、恶行举列、改过迁善四个层次。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(o,{paragraphs:["太上曰：祸福无门，惟人自召；善恶之报，如影随形。","是以天地有司过之神，依人所犯轻重，以夺人算。算减则贫耗，多逢忧患；人皆恶之，刑祸随之；吉庆避之，恶星灾之；算尽则死。又有三台北斗神君，在人头上，录人罪恶，夺其纪算。又有三尸神，在人身中，每到庚申日，辄上诣天曹，言人罪过。月晦之日，灶神亦然。凡人有过，大则夺纪，小则夺算。其过大小，有数百事，欲求长生者，先须避之。","是道则进，非道则退。不履邪径，不欺暗室；积德累功，慈心于物；忠孝友悌，正己化人；矜孤恤寡，敬老怀幼；昆虫草木，犹不可伤。","宜悯人之凶，乐人之善，济人之急，救人之危；见人之得，如己之得；见人之失，如己之失；不彰人短，不炫己长；遏恶扬善，推多取少；受辱不怨，受宠若惊；施恩不求报，与人不追悔；所谓善人，人皆敬之，天道佑之，福禄随之，众邪远之，神灵卫之；所作必成，神仙可冀。欲求天仙者，当立一千三百善；欲求地仙者，当立三百善。","苟或非义而动，背理而行；以恶为能，忍作残害；阴贼良善，暗侮君亲；慢其先生，叛其所事；诳诸无识，谤诸同学；虚诬诈伪，攻讦宗亲；刚强不仁，狠戾自用；是非不当，向背乖宜；虐下取功，谄上希旨；受恩不感，念怨不休；轻蔑天民，扰乱国政；赏及非义，刑及无辜；杀人取财，倾人取位；诛降戮服，贬正排贤；凌孤逼寡，弃法受赂；以直为曲，以曲为直；入轻为重，见杀加怒；知过不改，知善不为；自罪引他，壅塞方术；诅咒求直，嗜酒悖乱；骨肉忿争，男不忠良，女不柔顺；不和其室，不敬其夫；每好矜夸，常行妒忌；无行于妻子，失礼于舅姑；轻慢先灵，违逆上命；作为无益，怀挟外心；自咒咒他，偏憎偏爱；越井越灶，跳食跳人；损子堕胎，行多隐僻；晦腊歌舞，朔旦号怒；对北涕唾及溺，对灶吟咏及哭；又以灶火烧香，秽柴作食；夜起裸露，八节行刑；唾流星，指虹霓，辄指三光；久视日月，春月燎猎；对北恶骂，无故杀龟打蛇；如是等罪，司命随其轻重，夺其纪算。算尽则死，死有余责，乃殃及子孙。","又诸横取人财者，乃计其妻子家口以当之，渐至死丧。若不死丧，则有水火盗贼、遗亡器物、疾病口舌诸事，以当妄取之值。又枉杀人者，是易刀兵而相杀也。取非义之财者，譬如漏脯救饥，鸩酒止渴，非不暂饱，死亦及之。","夫心起于善，善虽未为，而吉神已随之；或心起于恶，恶虽未为，而凶神已随之。其有曾行恶事，后自改悔，诸恶莫作，众善奉行，久久必获吉庆；所谓转祸为福也。故吉人语善、视善、行善，一日有三善，三年天必降之福；凶人语恶、视恶、行恶，一日有三恶，三年天必降之祸。胡不勉而行之？"]}),i(l,{lines:[{text:"太上曰：祸福无门，惟人自召；善恶之报，如影随形。",tone:"总纲 · 先立根本",guide:"开篇先不要急着进入神祇系统，先抓住全篇真正的中心：祸福与善恶都与人的起心动念和所作所为相连。"},{text:"是以天地有司过之神……欲求长生者，先须避之。",tone:"秩序 · 强化警惕",guide:"这一段可先读成“天地间有一套追索人过的秩序”，重点不只在神名，而在于强调人的行为并不会做过就算。"},{text:"是道则进……欲求地仙者，当立三百善。",tone:"善行 · 落到日用",guide:"善并不是空泛口号，而是落实在不欺暗室、敬老怀幼、见人得失如己得失这些很具体的日常分寸里。"},{text:"苟或非义而动……乃殃及子孙。",tone:"恶行 · 镜照自身",guide:"这一长段不必一次记全，更适合当作一面镜子，看许多败坏与祸乱如何由细小偏差不断积成。"},{text:"夫心起于善……胡不勉而行之？",tone:"转向 · 留有余地",guide:"全篇最后不是把人锁死，而是留下改悔与转祸为福的路，这也是读这篇时很重要的收束处。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】注音-生僻字",tabindex:"-1"},[n("【原典层】注音 / 生僻字 "),e("a",{class:"header-anchor",href:"#【原典层】注音-生僻字","aria-label":'Permalink to "【原典层】注音 / 生僻字"'},"​")],-1)),i(s,{description:"这篇警策语气很强，先把常见却容易读错的字扫清，再回到句义。",items:[{char:"悌",pinyin:"tì",tag:"伦理字",note:"友悌，指兄弟之间和顺相处。"},{char:"恤",pinyin:"xù",tag:"常见误读",note:"恤寡之恤，有体察、抚恤之意。"},{char:"炫",pinyin:"xuàn",tag:"常见字",note:"炫己长，即夸耀自己的长处。"},{char:"讦",pinyin:"jié",tag:"生僻字",note:"攻讦，指揭人隐私、攻击他人短处。"},{char:"戾",pinyin:"lì",tag:"生僻字",note:"狠戾，指刚狠乖张，不近情理。"},{char:"鸩",pinyin:"zhèn",tag:"比喻字",note:"鸩酒，比喻看似止急，实则害命。"}]}),a[3]||(a[3]=e("h2",{id:"【原典层】分段",tabindex:"-1"},[n("【原典层】分段 "),e("a",{class:"header-anchor",href:"#【原典层】分段","aria-label":'Permalink to "【原典层】分段"'},"​")],-1)),i(d,{sections:[{label:"总纲",original:"太上曰：祸福无门，惟人自召；善恶之报，如影随形。",reading:"祸福无门，惟人自召；善恶之报，如影随形。",translation:"祸福并不是无端撞上来的，常常与人自己所召成的因由相关；善恶的结果，也会像影子一样慢慢跟上来。"},{label:"司过夺算",original:"是以天地有司过之神……欲求长生者，先须避之。",reading:"是以天地有司过之神 / 依人所犯轻重，以夺人算……欲求长生者，先须避之。",translation:"经文借司过、夺算的秩序语言，强调人的一举一动并非无后果，而是始终落在更大的衡量之中。",note:"这里的重点不是神秘细节本身，而是“有过必有追索”的警惕感。"},{label:"善行举要",original:"是道则进……欲求地仙者，当立三百善。",reading:"是道则进，非道则退……所谓善人，人皆敬之，天道佑之……欲求地仙者，当立三百善。",translation:"善并不飘在高处，而是一条条落在对人、对己、对物的具体分寸中；经文借此把“善”从抽象拉回日用。"},{label:"恶行举列",original:"苟或非义而动……乃殃及子孙。",reading:"苟或非义而动，背理而行……如是等罪，司命随其轻重，夺其纪算。算尽则死，死有余责，乃殃及子孙。",translation:"这一段集中铺开各种恶行，提醒人许多大的败坏与灾祸，往往都是从细小偏差、贪取、欺瞒与刚愎中慢慢积成。"},{label:"改过迁善",original:"又诸横取人财者……胡不勉而行之？",reading:"夫心起于善，善虽未为，而吉神已随之；或心起于恶，恶虽未为，而凶神已随之……胡不勉而行之？",translation:"全篇并未把人锁死在定罪里，而是指出：若能真正改悔、止恶行善，仍然有机会把后面的路慢慢转过来。"}]}),a[4]||(a[4]=e("h2",{id:"【原典层】关键词",tabindex:"-1"},[n("【原典层】关键词 "),e("a",{class:"header-anchor",href:"#【原典层】关键词","aria-label":'Permalink to "【原典层】关键词"'},"​")],-1)),i(h,{items:[{term:"感应",meaning:"人的起心动念与行为，终会带来相应后果。",context:"这不是空泛报应论，而是整篇最根本的警策逻辑。"},{term:"祸福",meaning:"并非无端降临，而与人的选择、习气与行为相关。",context:"经文开篇就把祸福拉回“惟人自召”的脉络里。"},{term:"司过",meaning:"象征记录、衡量、追索人过的一套秩序。",context:"可先理解为古典语境中的“行为不会凭空消失”。"},{term:"纪算",meaning:"寿数、福分、命数的古典表达。",context:"经文借此强化“过失会折损人的生命秩序”这一感受。"},{term:"善恶",meaning:"不只是抽象判断，而是落在具体言行、待人、处事上。",context:"整篇最重要的特点，就是把善恶拆成一条条可自照的日用行为。"},{term:"改悔",meaning:"承认过失、转身回头、重新止恶行善。",context:"全篇最后仍给人留下“转祸为福”的可能，而不只是定罪。"}]}),a[5]||(a[5]=m("",42))])}const D=p(u,[["render",b]]);export{y as __pageData,D as default};
